import{_ as o,c as t,o as i,ax as s}from"./chunks/framework.DHqKNX4U.js";const p=JSON.parse('{"title":"Job Queue Service","description":"","frontmatter":{},"headers":[],"relativePath":"services/job-queue.md","filePath":"services/job-queue.md"}'),a={name:"services/job-queue.md"};function n(c,e,r,d,l,h){return i(),t("div",null,e[0]||(e[0]=[s('<h1 id="job-queue-service" tabindex="-1">Job Queue Service <a class="header-anchor" href="#job-queue-service" aria-label="Permalink to &quot;Job Queue Service&quot;">​</a></h1><p>This document describes the architecture of the job queue system, including the sync cycle coordination mechanism and relevant configuration options.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><p>The job queue system is built on <a href="https://docs.bullmq.io/" target="_blank" rel="noreferrer">BullMQ</a> backed by Redis (Valkey). Two worker processes run independently:</p><ul><li><strong>Ingestion worker</strong> (<code>ingestion.worker.ts</code>) — processes the <code>ingestion</code> queue</li><li><strong>Indexing worker</strong> (<code>indexing.worker.ts</code>) — processes the <code>indexing</code> queue</li></ul><h3 id="queues" tabindex="-1">Queues <a class="header-anchor" href="#queues" aria-label="Permalink to &quot;Queues&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Queue</th><th>Jobs</th><th>Purpose</th></tr></thead><tbody><tr><td><code>ingestion</code></td><td><code>schedule-continuous-sync</code>, <code>continuous-sync</code>, <code>initial-import</code>, <code>process-mailbox</code>, <code>sync-cycle-finished</code></td><td>Email ingestion and sync orchestration</td></tr><tr><td><code>indexing</code></td><td><code>index-email-batch</code></td><td>Meilisearch document indexing</td></tr></tbody></table><h3 id="job-flow" tabindex="-1">Job Flow <a class="header-anchor" href="#job-flow" aria-label="Permalink to &quot;Job Flow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[schedule-continuous-sync] (repeating cron)</span></span>\n<span class="line"><span>    └→ [continuous-sync] (per ingestion source)</span></span>\n<span class="line"><span>           └→ [process-mailbox] × N (one per user mailbox)</span></span>\n<span class="line"><span>                  └→ [index-email-batch] (batched, on indexing queue)</span></span>\n<span class="line"><span>                  └→ [sync-cycle-finished] (dispatched by the last mailbox job)</span></span></code></pre></div><p>For initial imports, <code>initial-import</code> triggers the same <code>process-mailbox</code> → <code>sync-cycle-finished</code> flow.</p><h2 id="sync-cycle-coordination" tabindex="-1">Sync Cycle Coordination <a class="header-anchor" href="#sync-cycle-coordination" aria-label="Permalink to &quot;Sync Cycle Coordination&quot;">​</a></h2><p>Sync cycle completion (knowing when all mailboxes in a sync have finished) is coordinated via the <code>sync_sessions</code> PostgreSQL table rather than BullMQ&#39;s built-in flow/parent-child system.</p><p><strong>Why:</strong> BullMQ&#39;s <code>FlowProducer</code> stores the entire parent/child relationship in Redis atomically. For large tenants with thousands of mailboxes, this creates large Redis writes and requires loading all child job return values into memory at once for aggregation.</p><p><strong>How it works:</strong></p><ol><li>When <code>initial-import</code> or <code>continuous-sync</code> starts, it creates a <code>sync_sessions</code> row with <code>total_mailboxes = N</code>.</li><li>Each <code>process-mailbox</code> job atomically increments <code>completed_mailboxes</code> or <code>failed_mailboxes</code> when it finishes, and merges its <code>SyncState</code> into <code>ingestion_sources.sync_state</code> using PostgreSQL&#39;s <code>||</code> jsonb operator.</li><li>The job that brings <code>completed + failed</code> to equal <code>total</code> dispatches the <code>sync-cycle-finished</code> job.</li><li><code>sync-cycle-finished</code> reads the aggregated results from the session row and finalizes the source status.</li><li>The session row is deleted after finalization.</li></ol><h3 id="session-heartbeat" tabindex="-1">Session Heartbeat <a class="header-anchor" href="#session-heartbeat" aria-label="Permalink to &quot;Session Heartbeat&quot;">​</a></h3><p>Each <code>process-mailbox</code> job updates <code>last_activity_at</code> on the session every time it flushes an email batch to the indexing queue. This prevents the stale session detector from treating an actively processing large mailbox as stuck.</p><h3 id="stale-session-detection" tabindex="-1">Stale Session Detection <a class="header-anchor" href="#stale-session-detection" aria-label="Permalink to &quot;Stale Session Detection&quot;">​</a></h3><p>The <code>schedule-continuous-sync</code> job runs <code>SyncSessionService.cleanStaleSessions()</code> on every tick. A session is considered stale when <code>last_activity_at</code> has not been updated for 30 minutes, indicating the worker that created it has crashed before all mailbox jobs were enqueued.</p><p>When a stale session is detected:</p><ol><li>The associated ingestion source is set to <code>status: &#39;error&#39;</code> with a descriptive message.</li><li>The session row is deleted.</li><li>On the next scheduler tick, the source is picked up as an <code>error</code> source and a new <code>continuous-sync</code> job is dispatched.</li></ol><p>Already-ingested emails from the partial sync are preserved. The next sync skips them via duplicate detection (<code>checkDuplicate()</code>).</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Environment Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>SYNC_FREQUENCY</code></td><td><code>* * * * *</code></td><td>Cron pattern for continuous sync scheduling</td></tr><tr><td><code>INGESTION_WORKER_CONCURRENCY</code></td><td><code>5</code></td><td>Number of <code>process-mailbox</code> jobs that run in parallel</td></tr><tr><td><code>MEILI_INDEXING_BATCH</code></td><td><code>500</code></td><td>Number of emails per <code>index-email-batch</code> job</td></tr></tbody></table><h3 id="tuning-ingestion-worker-concurrency" tabindex="-1">Tuning <code>INGESTION_WORKER_CONCURRENCY</code> <a class="header-anchor" href="#tuning-ingestion-worker-concurrency" aria-label="Permalink to &quot;Tuning `INGESTION_WORKER_CONCURRENCY`&quot;">​</a></h3><p>Each <code>process-mailbox</code> job holds at most one parsed email in memory at a time during the ingestion loop. At typical email sizes (~50KB average), memory pressure per concurrent job is low. Increase this value on servers with more RAM to process multiple mailboxes in parallel and reduce total sync time.</p><h3 id="tuning-meili-indexing-batch" tabindex="-1">Tuning <code>MEILI_INDEXING_BATCH</code> <a class="header-anchor" href="#tuning-meili-indexing-batch" aria-label="Permalink to &quot;Tuning `MEILI_INDEXING_BATCH`&quot;">​</a></h3><p>Each <code>index-email-batch</code> job loads the <code>.eml</code> file and all attachments from storage into memory for text extraction before sending to Meilisearch. Reduce this value if the indexing worker experiences memory pressure on deployments with large attachments.</p><h2 id="resilience" tabindex="-1">Resilience <a class="header-anchor" href="#resilience" aria-label="Permalink to &quot;Resilience&quot;">​</a></h2><ul><li><strong>Job retries:</strong> All jobs are configured with 5 retry attempts using exponential backoff (starting at 1 second). This handles transient API failures from email providers.</li><li><strong>Worker crash recovery:</strong> BullMQ detects stalled jobs (no heartbeat within <code>lockDuration</code>) and re-queues them automatically. On retry, already-processed emails are skipped via <code>checkDuplicate()</code>.</li><li><strong>Partial sync recovery:</strong> Stale session detection handles the case where a worker crashes mid-dispatch, leaving some mailboxes never enqueued. The source is reset to <code>error</code> and the next scheduler tick retries the full sync.</li></ul>',30)]))}const b=o(a,[["render",n]]);export{p as __pageData,b as default};
